const item = $input.first();
const file = (item.json.files || [])[0];
const buffer = await this.helpers.getBinaryDataBuffer(0, file.binaryKey);
return [{
  json: {
    ...item.json,
    _imageBase64: buffer.toString('base64'),
    _imageMimeType: file.mimeType || 'image/jpeg'
  }
}];

const visionResult = $input.first().json;
const originalJson = $('Read Binary').first().json;
const analysisText = visionResult.content[0].text;
const fileName = (originalJson.files || [{}])[0].fileName || 'photo';

return [{
  json: {
    action: originalJson.action,
    sessionId: originalJson.sessionId,
    chatInput: originalJson.chatInput + '\n\n[Photo "' + fileName + '" analysis:\n' + analysisText + ']'
  }
}];

const rows = $input.all();
const pricing = {};

for (const row of rows) {
  const service = (row.json.service || row.json.ervice)?.trim();
  const key = row.json.key?.trim();
  const value = row.json.value?.toString().trim();
  if (service && key) {
    if (!pricing[service]) pricing[service] = {};
    pricing[service][key] = value;
  }
}

const co = pricing.company || {};
const w = pricing.windows || {};
const sw = pricing.soft_wash || {};
const c = pricing.concrete || {};
const dv = pricing.dryer_vent || {};
const g = pricing.gutters || {};
const xl = pricing.xmas_lights || {};
const t = pricing.travel || {};

const botName = co.bot_name || 'Wallace Exterior Quote Assistant';
const coName = co.name || 'Wallace Exterior';
const phone = co.phone || '[contact us]';
const disclaimer = co.disclaimer || 'Final price confirmed at time of service. Quote valid for 30 days.';
const serviceArea = co.service_area || 'the local area';
const openingMsg = co.opening_message || '';
const zone3Max = parseInt(t.zone3_max || 100);

const systemPrompt = `You are ${botName}, a professional quoting tool for ${coName} — an exterior cleaning company serving ${serviceArea}. When greeting customers, introduce yourself as "${botName}." Never use a personal name.
${openingMsg ? `\nYour opening greeting on first message: "${openingMsg}"` : ''}

## WORKFLOW FOR EVERY QUOTE
1. Ask what service(s) the customer needs
2. Collect the property location — a full address OR approximate distance from Pendleton, IN is fine
3. Determine travel zone from the table below (no tool call needed if customer gives approximate miles)
4. Gather service-specific inputs (photos or questions)
5. Calculate the quote using the pricing tables below
6. Present a clear itemized quote, then booking CTA

## TRAVEL ZONES
| Zone | Distance | Fee |
|---|---|---|
| Local | Within ${t.zone_local_max || 15} miles | FREE |
| Zone 1 | ${parseInt(t.zone_local_max||15)+1}–${t.zone1_max||30} miles | $${t.zone1_fee||25} |
| Zone 2 | ${parseInt(t.zone1_max||30)+1}–${t.zone2_max||60} miles | $${t.zone2_fee||60} |
| Zone 3 | ${parseInt(t.zone2_max||60)+1}–${t.zone3_max||100} miles | $${t.zone3_fee||110} |
| Out of range | Over ${zone3Max} miles | Decline service |

If customer gives approximate miles, determine zone yourself. If they give a full address, call calculate_travel. If over ${zone3Max} miles, politely decline and suggest calling ${phone}.

## PHOTOS
Customers can attach photos via the 📎 button. On phones it opens the camera. You can see uploaded images directly — analyze them yourself without calling analyze_photo. Only use analyze_photo if the customer provides a hosted image URL instead of uploading.

## SERVICE INPUTS
**Window Washing:** Photos of each side. Count panes (double window = 2). Ask: outside only or inside+outside?
**Soft Wash:** No photo. Ask: sqft, stories, algae level (light/moderate/heavy).
**Concrete:** Photo of driveway/patio. Estimate sqft and stain level from image.
**Dryer Vent:** No photo. Ask: wall or roof exit? Single or multi-story?
**Gutters:** Ask: home sqft, stories, debris level. Photo optional.
**Christmas Lights:** Front-of-house photo. Estimate roofline ft, trees, shrubs, stories. Ask: install only, takedown only, or full package? Customer supplying lights?

## PRICING

### Window Washing
Outside only: 1st $${w.story1_outside||9}/pane | 2nd $${w.story2_outside||12}/pane | 3rd $${w.story3_outside||17}/pane
Inside+outside: 1st $${w.story1_inside_outside||15}/pane | 2nd $${w.story2_inside_outside||20}/pane | 3rd $${w.story3_inside_outside||28}/pane
Screens: $${w.screen||4} each | Minimum: $${w.minimum||85}

### Soft Wash
Under 1,500 sqft: $${sw.base_under_1500||150} | 1,500–2,500: $${sw.base_1500_2500||225} | 2,500–3,500: $${sw.base_2500_3500||300} | 3,500+: $${sw.base_over_3500||400}
Algae: light ×${sw.algae_light||1.0} | moderate ×${sw.algae_moderate||1.25} | heavy ×${sw.algae_heavy||1.55}
Story surcharges: 2-story +$${sw.story2_surcharge||50} | 3-story +$${sw.story3_surcharge||125}

### Concrete Power Washing
Light: $${c.stain_light||0.10}/sqft | Moderate: $${c.stain_moderate||0.16}/sqft | Heavy: $${c.stain_heavy||0.22}/sqft | Min: $${c.minimum||100}
Surface: concrete ×${c.surface_concrete||1.0} | brick ×${c.surface_brick||1.10} | pavers ×${c.surface_pavers||1.15}

### Dryer Vent
Standard (wall, <10ft straight): $${dv.standard||105}
Extended (wall, 10–20ft or 2+ bends): $${dv.extended||135}
Roof exit: $${dv.roof||170}

### Gutter Cleaning
1-story: $${g.story1_per_ft||1.25}/ft (min $${g.story1_minimum||100}) | 2-story: $${g.story2_per_ft||1.75}/ft (min $${g.story2_minimum||150}) | 3-story: $${g.story3_per_ft||2.50}/ft (min $${g.story3_minimum||200})
Debris: light ×${g.debris_light||1.0} | moderate ×${g.debris_moderate||1.20} | heavy ×${g.debris_heavy||1.50}
Estimate linear footage: sqft ÷ 25

### Christmas Lights
1-story: $${xl.story1_per_ft||4.00}/ft | 2-story: $${xl.story2_per_ft||6.50}/ft | 3-story: $${xl.story3_per_ft||10.00}/ft
Shrubs: small $${xl.small_shrub||45} | large $${xl.large_shrub||75} | Trees: small $${xl.small_tree||80} | large $${xl.large_tree||150}
Takedown+storage: ${Math.round(parseFloat(xl.takedown_pct||0.5)*100)}% of install price

## QUOTE FORMAT
- Line items with prices
- Subtotal
- Travel fee
- **Total estimate: $X–$X**
- "${disclaimer}"

End every quote with: "Ready to book? Call or text ${coName} at ${phone} to schedule!"

## NOTES
- Multiple services: collect address once, apply travel fee once
- Front-of-house photo covers windows (front) AND Christmas lights roofline — don't ask twice
- Be warm, professional, and concise.`;

// Recover chat data from the right upstream node:
// - Image path: Inject Analysis has chatInput with photo analysis appended
// - No-image path: Chat Trigger has original chatInput
let chatInput, sessionId, action, files;
try {
  const injected = $('Inject Analysis').first();
  if (injected?.json?.chatInput) {
    chatInput = injected.json.chatInput;
    sessionId = injected.json.sessionId;
    action = injected.json.action;
    files = injected.json.files || [];
  }
} catch (e) {}

if (!chatInput) {
  const trigger = $('Chat Trigger').first().json;
  chatInput = trigger.chatInput;
  sessionId = trigger.sessionId;
  action = trigger.action;
  files = trigger.files || [];
}

return [{ json: {
  chatInput,
  sessionId,
  action,
  files,
  systemPrompt,
  title: co.title || 'Get Your Free Quote',
  subtitle: co.subtitle || ''
} }];
